    {
      "id": "gulf-war-settlement",
      "title": "Gulf War Settlement",
      "dateRange": "February 28-April 11, 1991",
      "question": "How victory in Kuwait became an argument about American power, coalition discipline, and limits."
    },
    {
      "id": "victory-afterlife",
      "title": "After Victory",
      "dateRange": "April 12-August 18, 1991",
      "question": "How the administration tried to convert success abroad into order at home and abroad."
    },
    {
      "id": "soviet-endgame",
      "title": "Soviet Endgame",
      "dateRange": "August 19-December 31, 1991",
      "question": "How the White House watched an adversary become a set of diplomatic, nuclear, and historical questions."
    },
    {
      "id": "economy-contestation",
      "title": "Economy and Contestation",
      "dateRange": "January 1-June 30, 1992",
      "question": "How recession, recovery, trade, taxes, and the early campaign reshaped the presidency."
    },
    {
      "id": "campaign-continuity",
      "title": "Campaign of Continuity",
      "dateRange": "July 1-November 3, 1992",
      "question": "How an incumbent made the case for stewardship against exhaustion, insurgency, and change."
    },
    {
      "id": "transition-accounting",
      "title": "Transition and Accounting",
      "dateRange": "November 4, 1992-January 20, 1993",
      "question": "How defeat turned into transfer, memory, personnel, and the final ordering of papers."
    }
